-- ── Hubstaff ──────────────────────────────────────────────
UPDATE tools SET
  short_description = $q$Time tracking and workforce management software with screenshots, activity levels, GPS tracking, and automated payroll for remote and field teams.$q$,
  pricing_model = $q$Freemium$q$,
  starting_price = $q$Free plan available; paid plans from $4.99/user/month (billed annually)$q$,
  founded_year = 2012,
  company_size = $q$51-200 employees$q$,
  headquarters = $q$Indianapolis, Indiana, USA$q$,
  languages = ARRAY[$q$English$q$]::text[],
  seo_meta_description = $q$Hubstaff review: time tracking, screenshots, GPS monitoring, and automated payroll for remote and field teams, plus pricing plans, features, pros and cons.$q$,
  og_description = $q$Hubstaff review: time tracking, screenshots, GPS monitoring, and automated payroll for remote and field teams, plus pricing plans, features, pros and cons.$q$,
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6' AND logo IS NULL AND website IS NOT NULL;









