INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Time Tracking$q$, $q$Start and stop timers from desktop, web, or mobile apps and attach tracked time to specific projects and tasks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Screenshots & Activity Levels$q$, $q$Capture configurable, periodic screenshots alongside activity percentages based on keyboard and mouse input.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$GPS & Geofencing$q$, $q$Track field employee locations and automatically start or stop time tracking when staff enter or leave a job site.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Automated Payroll$q$, $q$Pay employees and contractors automatically based on approved tracked hours, reducing manual payroll admin.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Online Invoicing$q$, $q$Generate client invoices directly from billable tracked time, streamlining agency and freelance billing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Project Budgeting$q$, $q$Set time or cost budgets per project and receive alerts before a project is at risk of going over.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Employee Scheduling$q$, $q$Build shift schedules and monitor attendance against scheduled hours for hourly or shift-based teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Reporting & Analytics$q$, $q$Review productivity, attendance, and payroll data through dashboards and exportable reports.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Integrations & API$q$, $q$Connect Hubstaff to project management, accounting, and communication tools, or build custom workflows via the API.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Idle Detection & Reminders$q$, $q$Automatically detect periods of inactivity and prompt or pause tracking so idle time isn't billed.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Detailed proof-of-work data, including screenshots and activity levels, is useful for client billing and remote oversight$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$GPS and geofencing features are well suited to field and mobile workforces$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Automated payroll and invoicing tied directly to tracked hours reduces manual administrative work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Cross-platform tracking apps cover desktop, web, and mobile with broad OS support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Tiered plans and add-ons let teams choose how much monitoring depth they actually need$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Screenshot and activity monitoring can feel invasive and hurt morale if not communicated clearly to employees$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$The free plan is limited to a single user and offers minimal reporting features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Add-ons for insights, extra screenshots, tasks, and data retention can meaningfully raise the effective cost per seat$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Keyboard/mouse-based activity scoring doesn't account for all forms of legitimate work, such as reading or calls$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Some deeper HR and payroll-compliance features are missing compared to dedicated HR-first platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Is Hubstaff free to use?$q$, $q$Hubstaff offers a free plan limited to a single user with basic time tracking, but paid plans are required for team features, advanced monitoring, and reporting.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Does Hubstaff take screenshots of employees' screens?$q$, $q$Yes, screenshot capture is available on paid plans and is configurable per team or project, including how often screenshots are taken and whether employees are notified.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Can Hubstaff track GPS location?$q$, $q$Yes, GPS tracking and geofencing are available for mobile and field teams, allowing automatic clock-in and clock-out based on job-site location.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Does Hubstaff handle payroll?$q$, $q$Yes, Hubstaff supports automated payroll and payments to employees and contractors based on approved tracked hours.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$What platforms does Hubstaff support?$q$, $q$Hubstaff provides desktop apps for Windows, Mac, and Linux, a browser extension, and mobile apps for iOS and Android.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Client Billing for Agencies$q$, $q$Agencies use tracked time, screenshots, and activity data as documented evidence when invoicing clients for hourly work.$q$, $q$Digital agencies and consultancies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Remote Team Productivity Oversight$q$, $q$Managers monitor distributed employees' time, app usage, and activity levels without requiring manual status check-ins.$q$, $q$Distributed and remote-first companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Field Service Workforce Tracking$q$, $q$GPS and geofenced tracking automatically log when mobile staff arrive at and leave job sites for accurate attendance records.$q$, $q$Construction, home care, and logistics companies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Freelancer Time & Invoice Tracking$q$, $q$Independent contractors log billable hours per project and generate client invoices directly from tracked time.$q$, $q$Freelancers and independent contractors$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Free$q$, $q$Free$q$, $q$N/A$q$, $q$["Limited to 1 user","Basic time tracking","Limited reporting","Desktop and mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Starter$q$, $q$$4.99/user/month billed annually (or $7/user/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Time tracking with screenshots","Activity levels","Basic reporting","Limited integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Team$q$, $q$$10/user/month billed annually (or $12/user/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["GPS and geofenced tracking","Employee scheduling","Advanced reporting","Expanded integrations","Project budgeting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$Enterprise$q$, $q$$25/user/month, billed annually only$q$, $q$Annual$q$, $q$["Automated payroll","Priority support","Advanced security controls","Dedicated onboarding assistance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hubstaff is a time tracking and workforce management platform built for remote, hybrid, and field-based teams. Founded in 2012 and headquartered in the Indianapolis, Indiana area, the company has grown into one of the more established names in employee monitoring and productivity software, serving businesses that need clear visibility into how billable hours are spent.$q$, $q$At its core, Hubstaff combines time tracking with optional screenshots, app and URL usage, and activity level percentages that estimate keyboard and mouse engagement during a tracked session. Data flows into dashboards and reports that managers can use to review team output, spot idle time, and justify client invoices with timestamped evidence.$q$, $q$Beyond monitoring, Hubstaff has expanded into adjacent workflows: GPS and geofenced time tracking for field crews, automated payroll and invoicing tied directly to tracked hours, project budgeting and cost estimation, and scheduling tools for shift-based teams. Integrations with project management, accounting, and communication tools round out the platform for teams that want time data to flow into their existing stack rather than live in a silo.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$who-hubstaff-is-for$q$, $q$Who Hubstaff Is For$q$, 2, ARRAY[$q$Hubstaff is best suited to distributed and remote-first companies, especially those that bill clients by the hour and need documented proof of work. Digital agencies, software consultancies, and outsourced development shops are common users, since screenshots and activity data double as an audit trail for client invoices and dispute resolution.$q$, $q$Freelancers and contractors who need to demonstrate hours worked to a client, or who simply want a lightweight way to log time across multiple projects, also fit the tool well. Its per-project time tracking and budget alerts help independent workers avoid quietly overrunning a fixed-fee engagement.$q$, $q$Field service, construction, logistics, and home-care businesses are another core audience, thanks to GPS location tracking, geofenced clock-in/out, and job-site scheduling. For these teams, Hubstaff functions less like a monitoring tool and more like an operational system for tracking where mobile staff are and when they worked.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations with a strong trust-based or autonomy-first culture may find the screenshot and activity-percentage features at odds with how they manage people. Employee monitoring software like Hubstaff can create morale friction if it is rolled out without clear communication about what is tracked and why.$q$, $q$Very small teams or solo users with simple needs may find the paid tiers more than they require; the free plan is limited to a single user and lacks reporting depth, so casual time-tracking use cases may be better served by a simpler, cheaper tool.$q$, $q$Companies looking for a full HR information system, benefits administration, or a payroll platform that isn't tied to hourly time tracking will also find Hubstaff's scope narrower than dedicated HR or payroll-first software, since its payroll features are built around paying out tracked hours rather than full-service HR compliance.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Time tracking sits at the center of Hubstaff, available through desktop apps for Windows, Mac, and Linux, a browser extension, and mobile apps for iOS and Android. Tracked time can be tied to specific projects and tasks, with optional idle detection and reminders to start or stop the timer.$q$, $q$Activity monitoring adds configurable screenshots, activity levels based on keyboard and mouse input, and app and URL usage tracking, giving managers a picture of how time was spent without requiring manual status updates. Field teams get GPS tracking and geofencing so hours can be automatically logged when staff enter or leave a job site.$q$, $q$On the operations side, Hubstaff offers automated payroll and payments based on approved hours, client invoicing, project budgets with overrun alerts, employee scheduling, and reporting and analytics dashboards. An API and integrations with tools like Trello, Asana, QuickBooks, and Slack let teams connect time data to the rest of their workflow.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', $q$the-hubstaff-experience$q$, $q$The Hubstaff Experience$q$, 2, ARRAY[$q$Setting up Hubstaff is generally straightforward: an admin creates an organization, invites team members, and configures which monitoring features, such as screenshots, activity levels, and URL or app tracking, are enabled per team or project. The web dashboard centralizes reports, timesheets, and settings.$q$, $q$The desktop and mobile trackers are functional rather than flashy, running quietly in the background with a simple start and stop timer and periodic activity capture. Notifications nudge users who forget to track time, and managers can review and approve timesheets before payroll runs.$q$, $q$Overall, the experience favors clarity and control for managers over a particularly polished end-user experience; employees mostly interact with a minimal timer widget, while the bulk of the configuration, reporting, and payroll workflow lives on the admin side of the dashboard.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
