INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7a1260e7-5c8c-4d8c-bcb5-ddf9865100d6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$TypeAhead autocomplete$q$, $q$Predicts and suggests full sentences as you type in text fields across most websites, adapting to context and your own writing style.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$AI chat assistant$q$, $q$A conversational assistant for drafting, editing, and answering questions, with real-time web search and source citations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Browser extension$q$, $q$A Chrome extension brings TypeAhead and chat directly into Gmail, Google Docs, LinkedIn, and most other text fields online.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Custom personas$q$, $q$Configurable assistant profiles that adjust tone, expertise, or role for different writing tasks, with more personas on paid plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$AI tool and template library$q$, $q$A large collection of pre-built prompts and templates for tasks like outlining, summarizing, rewriting, and replying to email.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Real-time web search with citations$q$, $q$Chat responses can pull in current information from the web and cite the sources used.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Document editor$q$, $q$A built-in web app editor for composing and revising longer documents outside of a specific third-party site.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Experimental Personal Assistant$q$, $q$An early-access feature that attempts to automate simple, repetitive tasks directly within the browser.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Tiered usage plans$q$, $q$Free, Premium, and Ultra plans scale monthly message and generation allowances to match usage needs.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Free plan lets new users try TypeAhead and chat before paying$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Autocomplete works across many websites, not just a single editor$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Integrates directly with Gmail, Google Docs, and LinkedIn via browser extension$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Large library of templates covers a wide range of common writing tasks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Chat assistant supports real-time web search with citations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Message limits on the Free and Premium plans can feel restrictive for heavy use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Ultra plan pricing is a significant step up from Premium$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$No public API for developers wanting to build custom integrations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Browser-extension-centric design may not suit users who want a single dedicated app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Experimental features like the Personal Assistant are still early and can be inconsistent$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Is HyperWrite free to use?$q$, $q$Yes, HyperWrite offers a free account with a limited number of monthly AI generations. Paid Premium and Ultra plans increase or remove those limits and add extra features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$What is TypeAhead?$q$, $q$TypeAhead is HyperWrite's predictive autocomplete feature that suggests full sentences as you type across most websites, adapting to context and your writing style.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Does HyperWrite work inside Gmail and Google Docs?$q$, $q$Yes. HyperWrite's Chrome browser extension injects TypeAhead suggestions and chat access into Gmail, Google Docs, LinkedIn, and most other text fields on the web.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$What's the difference between the Premium and Ultra plans?$q$, $q$Premium includes a set monthly allowance of AI messages and a smaller number of custom personas, while Ultra offers unlimited AI messages, more personas, and earlier access to experimental features.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Who created HyperWrite?$q$, $q$HyperWrite is built by OthersideAI, a company founded in 2020 by Matt Shumer and Jason Kuperberg and based in New York.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Faster content marketing drafts$q$, $q$Use TypeAhead and template prompts to draft blog posts, social captions, and marketing copy more quickly.$q$, $q$Content marketers and bloggers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Quicker email and outreach replies$q$, $q$Rely on browser-wide autocomplete inside Gmail and other webmail clients to speed up daily correspondence.$q$, $q$Salespeople, recruiters, and support staff$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Research-backed writing with citations$q$, $q$Use the chat assistant's real-time web search and citation support to ground essays, summaries, or reports in sources.$q$, $q$Students and researchers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Lightweight in-house content support$q$, $q$Handle marketing, customer emails, and website copy without hiring a dedicated writer or content team.$q$, $q$Small business owners and solo founders$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Limited monthly AI generations","Access to TypeAhead autocomplete","Browser extension for Gmail, Docs, and LinkedIn","Basic chat assistant access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Premium$q$, $q$$19.99/month (or $16/month billed annually)$q$, $q$Monthly or annual$q$, $q$["250 AI messages per month","Citations and real-time web info","3 custom personas","Hundreds of AI tools and templates","Unlimited TypeAheads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$Ultra$q$, $q$$44.99/month (or $29/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Unlimited AI messages","10 custom personas","First access to experimental features","Unlimited TypeAheads"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HyperWrite is an AI writing assistant built by OthersideAI, the New York-based startup founded in 2020 by Matt Shumer and Jason Kuperberg. Available at hyperwriteai.com, it packages large language model capabilities into a browser extension, web app, and chat interface aimed at everyday writing tasks rather than a single specialized workflow. Rather than positioning itself as a single-purpose editor, HyperWrite blends predictive autocomplete, conversational AI, and a library of pre-built writing templates into one subscription product. HyperWrite launched during the early wave of consumer-facing generative AI products and has since positioned itself less as a single blank-page editor and more as an assistant that follows the user around the web.$q$, $q$The product's signature feature is TypeAhead, a predictive autocomplete that suggests full sentences as a user types across most websites, including Gmail, Google Docs, and LinkedIn. Alongside TypeAhead sits an AI chat assistant that can search the web, cite sources, and adopt configurable "personas" tuned to different writing styles or roles. HyperWrite also offers an experimental Personal Assistant feature designed to carry out simple browser-based tasks on a user's behalf.$q$, $q$HyperWrite is offered as a freemium product: a free account provides a limited number of monthly AI generations, while paid Premium and Ultra plans raise or remove those limits and unlock additional personas and features. This tiered structure makes HyperWrite accessible to casual users while still monetizing heavier, professional use through its subscription plans.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$who-its-for$q$, $q$Who HyperWrite Is For$q$, 2, ARRAY[$q$HyperWrite suits individuals who write frequently across many different websites and tools rather than in one dedicated editor. Content marketers, bloggers, and social media managers can use its templates and TypeAhead suggestions to draft posts, captions, and outlines faster, while the chat assistant's web search and citation support help ground content in real sources. Small business owners and solo founders who handle their own marketing, customer emails, and website copy can also use HyperWrite as a lightweight substitute for a dedicated writer or larger content team.$q$, $q$Professionals who spend much of their day composing email and short-form communication, such as salespeople, recruiters, and customer support staff, are also a natural fit, since the browser extension follows them into Gmail and other webmail clients. Students and researchers can lean on the citation-aware chat mode when drafting essays, summaries, or study notes that need to reference outside material.$q$, $q$Because the free tier is genuinely usable for light, occasional writing, HyperWrite also appeals to individuals who are simply curious about AI writing tools and want to try autocomplete and chat features before committing to a paid plan or a more specialized product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need a dedicated SEO content platform with keyword research, content scoring, and deep search-optimization workflows will likely find HyperWrite's feature set too general; it is built around everyday writing assistance rather than search-ranking-focused content production. Users who prefer to keep all of their writing inside a single dedicated document editor, rather than a browser extension layered over many sites, may find HyperWrite's approach less convenient than an all-in-one word processor with built-in AI.$q$, $q$Developers and businesses hoping to build custom integrations or embed HyperWrite's models into their own products should also look elsewhere, since the tool does not expose a public API and is designed for direct, individual use through its extension and web app rather than programmatic access.$q$, $q$Heavy daily users of AI chat may find the message allowances on the Free and Premium plans limiting, and the jump in price to the unlimited Ultra tier is significant; budget-conscious users who need very high message volumes may want to compare costs against other subscription-based AI writing tools before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$HyperWrite's core feature is TypeAhead, an autocomplete engine that predicts and suggests full sentences as a user types in supported text fields across the web, adapting suggestions to the surrounding context and, over time, to the user's own writing style.$q$, $q$A conversational AI chat mode sits alongside TypeAhead, offering real-time web search with citations so that answers and drafts can be traced back to sources. Paid plans add custom "personas," configurable assistant profiles that let users tailor tone, expertise, or role for different writing scenarios, along with access to a wide library of pre-built AI tools and templates covering tasks like outlining, summarizing, rewriting, and replying to email.$q$, $q$The Chrome browser extension is central to the experience, injecting HyperWrite's suggestions and chat access directly into Gmail, Google Docs, LinkedIn, and most other text fields online. Higher-tier plans also grant early access to experimental features, including a Personal Assistant capability aimed at automating simple, repetitive browser tasks. HyperWrite also includes a standalone document editor within its web app for longer drafts, giving users a home base for writing that does not depend on visiting a third-party site first.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', $q$experience$q$, $q$The HyperWrite Experience$q$, 2, ARRAY[$q$Getting started with HyperWrite typically means creating a free account and installing the Chrome extension, after which TypeAhead suggestions and a chat sidebar become available almost anywhere text can be entered on the web. The onboarding flow emphasizes quick wins, letting new users try autocomplete in a familiar tool like Gmail or Google Docs before exploring the wider template library and chat personas.$q$, $q$Because HyperWrite lives largely inside the browser rather than as a separate destination, using it feels less like switching to a new app and more like an enhancement layered on top of existing workflows. The chat interface and persona system give the experience some flexibility, letting the same account serve different writing needs, from casual email replies to more structured long-form drafts.$q$, $q$Upgrading from Free to Premium or Ultra mainly changes the ceiling on monthly usage and unlocks more personas and early features, rather than introducing a substantially different interface, so the day-to-day experience stays consistent as needs grow. Overall, HyperWrite is designed to be lightweight and unobtrusive, prioritizing speed and convenience over a heavier, standalone editing environment.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e0af591-0b3b-4416-988d-d1b31d3ab630', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
