INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Cross-network analytics$q$, $q$Aggregates performance metrics across Instagram, Facebook, TikTok, LinkedIn, X, Pinterest, Threads, and YouTube into unified, comparable dashboards.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Automated, white-label reporting$q$, $q$Generates scheduled PDF or email reports with custom branding, saving teams from manually compiling performance decks for clients or leadership.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Content scheduling and publishing$q$, $q$Plan and auto-publish posts from a shared content calendar across all supported social networks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Social listening$q$, $q$Monitors mentions, hashtags, comments, and competitor activity so teams can react quickly and benchmark against rivals.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Competitor benchmarking$q$, $q$Compares account performance against competitor profiles to contextualize growth, engagement, and content strategy.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Team collaboration and approvals$q$, $q$Role-based permissions and content approval workflows let teams review posts before publishing, useful for agencies managing clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Campaign and label organization$q$, $q$Tags and organizes content and profiles by campaign or client to reduce confusion across larger accounts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$AI-assisted content ideas$q$, $q$Surfaces AI-generated content suggestions and caption help to speed up post ideation.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Mobile apps$q$, $q$iOS and Android apps let teams check analytics and manage posting on the go.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Deep, historical analytics that go beyond native platform insights$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Strong automated, white-label reporting for agencies and client work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Supports a wide range of major social networks in one dashboard$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Collaboration and approval workflows suited to agency and team use$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Clean, analytics-focused interface that is not overloaded with features$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Pricing scales with users and profiles, which can get expensive for agencies with many clients$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Less suited to solo creators or very small budgets compared to lighter tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Feature set is narrower than all-in-one marketing suites with CRM or e-commerce integrations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Advanced features like social listening and unlimited posts are gated to higher-tier plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Some users may find scheduling and content creation less robust than the analytics side$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$What social networks does Iconosquare support?$q$, $q$Iconosquare supports Instagram, Facebook, TikTok, LinkedIn, X (Twitter), Pinterest, Threads, and YouTube for analytics, scheduling, and listening.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Does Iconosquare offer a free trial?$q$, $q$Yes, Iconosquare offers a 14-day free trial that does not require a credit card to start.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$How much does Iconosquare cost?$q$, $q$Plans start around $39/month for the Launch plan, with Scale and Excel tiers priced higher based on users, profiles, and features, plus a Custom plan for larger agencies.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Is Iconosquare good for agencies?$q$, $q$Yes, its multi-client dashboards, white-label reporting, content approval workflows, and campaign labeling are built with agency use cases in mind.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Does Iconosquare include social listening?$q$, $q$Yes, social listening and competitor monitoring are included starting on its mid-tier plans.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Client performance reporting$q$, $q$Agencies use Iconosquare's automated, white-label reports to show clients clear, branded performance summaries without manual spreadsheet work.$q$, $q$Social media agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Multi-channel content scheduling$q$, $q$Marketing teams plan and auto-publish content across several networks from one shared content calendar.$q$, $q$In-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Competitor and brand monitoring$q$, $q$Brands track mentions, hashtags, and competitor activity to react quickly and benchmark their social strategy.$q$, $q$Brand and community managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Team-based content approval$q$, $q$Teams use role permissions and approval workflows to review posts before they go live across multiple client or brand accounts.$q$, $q$Multi-account social teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Launch$q$, $q$$39$q$, $q$per month$q$, $q$["1 user","Standard analytics and reports","100 posts per month","Core scheduling tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Scale$q$, $q$$83$q$, $q$per month$q$, $q$["3 users","Unlimited posts","Campaign analytics","Social listening","Community management and collaboration tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Excel$q$, $q$$139$q$, $q$per month$q$, $q$["6 users","Unlimited posts","Dedicated customer success manager","White-label reporting","Priority support and unlimited data retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$Custom$q$, $q$Contact for pricing$q$, $q$custom$q$, $q$["20+ social profiles","Flexible user and profile limits","Tailored onboarding","Enterprise-level support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Iconosquare is an analytics-first social media management platform founded in 2011 in Limoges, France. It was originally built around deep Instagram analytics before expanding to cover Facebook, TikTok, LinkedIn, X (Twitter), Pinterest, Threads, and YouTube, giving marketers a single dashboard to track performance across most of the networks brands actually use day to day.$q$, $q$The platform built its early reputation by surfacing historical and granular metrics that native platform insights did not offer, which made it a go-to tool for agencies and brands that needed to defend social media budgets with hard numbers. That analytics-first identity still shapes how the product is organized today.$q$, $q$Iconosquare has since grown into a fuller social media management suite, layering scheduling, publishing, social listening, and automated reporting on top of its analytics core. It positions itself less as a jack-of-all-trades scheduler and more as a data-driven command center for teams that need to prove return on investment from their social presence.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$who-iconosquare-is-for$q$, $q$Who Iconosquare Is For$q$, 2, ARRAY[$q$Social media managers and marketing teams who regularly need to report performance to leadership, clients, or stakeholders are a strong fit. Iconosquare's automated, white-label reports save the manual work of pulling numbers from multiple platforms into a slide deck every month.$q$, $q$Agencies juggling several client accounts benefit from the multi-profile dashboards, campaign labeling, and content approval workflows, which make it easier to keep client work organized and to hand off polished analytics without exposing the underlying tool to the client directly.$q$, $q$Brands that run both organic and paid social and want a unified view of engagement, competitor benchmarking, and content performance will find the combination of analytics, social listening, and scheduling genuinely useful rather than just a convenience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo creators or very small businesses with a single social account and a limited budget may find the pricing hard to justify next to lighter, cheaper, or free scheduling tools that cover their basic needs without the analytics depth.$q$, $q$Teams that need social media management folded into a broader marketing stack, such as CRM, email, or e-commerce integrations, may prefer an all-in-one marketing platform instead, since Iconosquare's focus stays fairly narrow around social analytics and publishing.$q$, $q$Organizations whose primary channels sit outside Iconosquare's supported networks, or who need only a very small number of profiles, are likely to be paying for capacity and features they will not use given how the plans scale by user and profile counts.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Iconosquare aggregates dozens of metrics across connected networks into unified dashboards, letting teams compare performance over custom date ranges, benchmark against competitors, and export white-label PDF or scheduled email reports without manual data pulls.$q$, $q$Its publishing tools let teams plan, schedule, and auto-publish content from a shared content calendar across Instagram, Facebook, TikTok, LinkedIn, X, Pinterest, Threads, and YouTube, alongside AI-assisted content suggestions to help speed up ideation for captions and posts.$q$, $q$Social listening and monitoring features track mentions, comments, hashtags, and competitor activity, while collaboration tools such as role-based permissions, content approval flows, and campaign labels support teams and agencies managing multiple accounts and clients from one workspace.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', $q$the-iconosquare-experience$q$, $q$The Iconosquare Experience$q$, 2, ARRAY[$q$New users generally find the interface clean and less cluttered than some all-in-one competitors, since the product is built around analytics dashboards first, with scheduling and listening tools layered in a way that keeps the reporting experience central rather than an afterthought.$q$, $q$Support resources include a self-serve knowledge base and, on higher-tier plans, a dedicated customer success manager and personalized onboarding, which reviewers often cite as a meaningful upgrade for agencies that need hands-on help configuring reports and workflows.$q$, $q$Overall, the day-to-day experience leans toward reporting and insight generation rather than heavy content creation, so teams that value clear, presentable analytics tend to get the most value, while those wanting a creative-first publishing hub may feel the toolset is more report-driven than they expected.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('055370e8-fd15-4fdf-9dad-531fc3b6a3c9', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
