INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0a25dd23-914b-48e4-8554-6252f6edb666', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Unlimited devices per account$q$, $q$A single IDrive plan can back up an unlimited number of computers, phones, and tablets instead of charging per device.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Continuous and scheduled backup$q$, $q$Files can be backed up in real time as they change or on a schedule you define, reducing the risk of data loss between backups.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Private encryption key$q$, $q$Users can choose a private key so that data is encrypted end-to-end and cannot be decrypted by IDrive itself.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$IDrive Express$q$, $q$Physical hard drives can be shipped to and from IDrive for faster initial backups or large-scale restores.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Snapshot version history$q$, $q$Multiple previous versions of files are retained, helping recover from accidental changes, deletion, or ransomware.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Hybrid local and cloud backup$q$, $q$Data can be backed up to a local drive or NAS in addition to the cloud for extra redundancy.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Server and NAS support$q$, $q$Physical servers, virtual machines, and NAS devices can be backed up alongside standard desktops and laptops.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$IDrive e2 object storage$q$, $q$An S3-compatible object storage product for developers and businesses that need programmatic cloud storage.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Mobile apps with camera backup$q$, $q$iOS and Android apps let users automatically back up photos and videos from their phones.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Centralized admin console$q$, $q$Team and Business plans include an admin dashboard for managing storage, users, and devices across an organization.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Low cost per terabyte compared to many mainstream cloud storage competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Unlimited devices covered under a single account and plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Optional private encryption key for end-to-end data control$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Physical drive shipping available for large initial backups or restores$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Supports servers, NAS devices, and multi-user business backup$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Interface and settings can feel more complex than simpler consumer backup tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Introductory first-year pricing on some plans renews at a higher rate$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Designed around backup and restore rather than real-time collaborative file sync$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Restoring very large amounts of data over the internet can be slow without using the express drive option$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Overage charges can apply if stored data exceeds the plan's storage limit$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Is IDrive free to use?$q$, $q$IDrive offers a free Basic plan with a limited amount of storage and no credit card required, in addition to its paid personal, team, and business plans.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$What devices and platforms does IDrive support?$q$, $q$IDrive supports Windows, Mac, iOS, Android, and Linux, along with backup for NAS devices and physical or virtual servers on business plans.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$How does IDrive keep data secure?$q$, $q$IDrive encrypts data in transit and at rest, and users can enable a private encryption key so that only they can decrypt their backed-up files.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Can IDrive back up more than one computer on a single plan?$q$, $q$Yes, IDrive plans allow an unlimited number of devices to be backed up under one account, unlike storage services that charge per device.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Does IDrive pricing change after the first year?$q$, $q$Some personal plans include first-year promotional pricing, and renewal rates can be higher, so it's worth checking the current plan terms before subscribing.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Whole-household device backup$q$, $q$Back up every family member's laptop, phone, and tablet to one shared storage plan instead of managing separate subscriptions per device.$q$, $q$Individuals and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Centralized small business backup$q$, $q$IT admins can back up employee computers, shared drives, and servers under one managed account with centralized visibility.$q$, $q$Small businesses and IT administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Server and NAS disaster recovery$q$, $q$Protect physical servers, virtual machines, and network-attached storage with scheduled backups and offsite copies for recovery after hardware failure.$q$, $q$IT professionals and system administrators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Ransomware and version recovery$q$, $q$Use snapshot-based version history and a private encryption key to roll back files to a clean state after accidental deletion or a ransomware incident.$q$, $q$Security-conscious individuals and businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, $q$["10 GB of backup storage","No credit card required","Backup for one computer","Access via web and mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Personal$q$, $q$From $99.50/year for 5 TB$q$, $q$Annual$q$, $q$["Unlimited devices on one account","Storage tiers from 5 TB up to 100 TB","Optional private encryption key","IDrive Express physical drive restore option"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Team$q$, $q$From $99.50/year$q$, $q$Annual$q$, $q$["Shared storage pool for multiple users","Multiple computers per user","Centralized admin management","Scales up to larger user and storage tiers"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$Business$q$, $q$From $99.50/year$q$, $q$Annual$q$, $q$["Unlimited users and computers","Server and NAS backup support","Higher storage tiers for larger organizations","Centralized admin console"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$IDrive is a cloud backup and storage service operated by IDrive Inc., a privately held technology company headquartered in Calabasas, California. The company traces its roots to Pro Softnet Corporation, later rebranded as IDrive, and has spent decades building out backup, sync, and remote-access products for consumers and businesses.$q$, $q$At its core, IDrive lets a single account back up an unlimited number of computers, phones, and tablets to encrypted cloud storage, rather than tying storage to one device the way many competitors do. Backups can run continuously or on a schedule, and users can restore individual files or entire systems from the web, desktop, or mobile apps.$q$, $q$Beyond consumer backup, IDrive has expanded into adjacent products, including IDrive e2 (S3-compatible object storage) and business-focused backup for servers and NAS devices. This positions it as both a low-cost personal backup option and a broader data-protection platform for teams and IT administrators.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$who-its-for$q$, $q$Who IDrive Is For$q$, 2, ARRAY[$q$IDrive suits individuals and families who own several devices and want them all protected under one affordable plan, rather than paying per device or juggling multiple storage subscriptions. Its per-terabyte pricing tends to undercut mainstream consumer cloud storage services, which appeals to budget-conscious users with large photo, video, or document libraries.$q$, $q$It's also a fit for small businesses and IT-managed teams that need centralized backup across many employee computers, plus support for physical and virtual servers or NAS devices. The Team and Business tiers add shared storage pools and administrative oversight that solo consumer tools typically lack.$q$, $q$Security- and continuity-minded users benefit from IDrive's optional private encryption key, snapshot-based version history, and IDrive Express physical drive shipping, which are useful for anyone who wants an extra layer of control over restores or ransomware recovery beyond standard cloud sync.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users who primarily want real-time collaborative file sync, the kind offered by Dropbox or Google Drive, may find IDrive's backup-first design less convenient, since it is oriented around scheduled or continuous backup and restore rather than live multi-user document editing.$q$, $q$People who want the absolute simplest, most minimal interface may find IDrive's settings, storage tiers, and add-on products (like IDrive e2) more involved than a bare-bones backup app. The added configuration options are powerful but can feel like overkill for someone who just wants a single toggle to protect one laptop.$q$, $q$Larger enterprises with strict compliance or dedicated account-management requirements beyond what IDrive's published plans cover, or organizations that need storage without any tiered capacity caps, may need to evaluate whether IDrive's current plan structure and support model matches their internal requirements before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$IDrive's backup agents run on Windows, Mac, iOS, Android, and Linux, and a single account can cover an unlimited number of devices rather than charging per machine. Backups can be continuous or scheduled, and users can browse and restore individual files or full system images from a web console or local app.$q$, $q$Data is protected with AES-256 encryption, and users can opt into a private encryption key that only they control, meaning IDrive itself cannot decrypt the data without it. Snapshot-based version history keeps multiple prior states of backed-up files, which supports recovery from accidental deletion or ransomware incidents.$q$, $q$For larger restores or first-time backups of very large datasets, IDrive Express lets customers ship a physical drive rather than relying solely on network transfer. Business and server users get support for NAS devices, physical/virtual servers, hybrid local-plus-cloud backup, and a centralized admin console for managing multiple users and machines.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', $q$idrive-experience$q$, $q$The IDrive Experience$q$, 2, ARRAY[$q$Getting started with IDrive typically involves creating an account, installing the desktop or mobile app, and selecting files, folders, or entire drives to protect. First backups of large datasets can take time over a standard internet connection, which is where the option to mail in a physical drive becomes useful for bigger jobs.$q$, $q$Day to day, the web dashboard and mobile apps let users monitor backup status, browse versioned file history, and trigger restores across their connected devices, including automatic camera backup from phones. Business and Team plan administrators get an additional console for managing storage allocation and user access across an organization.$q$, $q$Overall, the experience trades some interface simplicity for depth of control and low per-terabyte cost, making it feel more like a configurable data-protection platform than a single-purpose consumer app, which tends to reward users willing to spend a little time on setup.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd90d7f0-266d-4308-84e4-03884e03b80c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
