INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Merge PDF$q$, $q$Combine multiple PDF files into a single document in a chosen order, directly in the browser.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Split PDF$q$, $q$Extract specific pages or divide a PDF into multiple separate files.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Compress PDF$q$, $q$Reduce file size for easier sharing and storage while aiming to preserve visual quality.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$PDF Conversion$q$, $q$Convert PDFs to and from Word, Excel, PowerPoint, and image formats like JPG.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$PDF Editor$q$, $q$Add text, images, shapes, and annotations directly onto PDF pages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$eSign$q$, $q$Request signatures from others or add your own digital signature to a document.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$OCR$q$, $q$Convert scanned pages into searchable, selectable, and copyable text.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Protect and Unlock PDF$q$, $q$Add password encryption to a PDF or remove an existing password when authorized.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Developer API$q$, $q$REST API for integrating PDF merging, splitting, and conversion into third-party applications.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Mobile and Desktop Apps$q$, $q$Native iOS and Android apps plus Windows and Mac desktop applications for offline-adjacent access.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Wide range of PDF tools available for free with no account required for basic tasks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Simple, single-purpose interface that keeps the learning curve very low$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Available across web, iOS, Android, and desktop (Windows/Mac)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Developer API makes it straightforward to embed PDF processing into other products$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Reasonably priced Premium tier compared to full desktop PDF editing suites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Free tier imposes file-size and daily usage limits, and shows ads$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Editing capabilities are shallower than dedicated tools like Adobe Acrobat Pro$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Business pricing requires contacting sales rather than transparent self-serve pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Cloud-based processing may not suit organizations with strict data residency or offline requirements$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Some advanced workflows (heavy batch automation) really require the paid API or Business plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Is iLovePDF free to use?$q$, $q$Yes. iLovePDF offers a free Basic plan with access to its core tools, though it applies limits on file size, batch processing, and daily use, and shows ads. A paid Premium plan removes most of those limits.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Does iLovePDF have a mobile app?$q$, $q$Yes, iLovePDF offers native apps for iOS and Android in addition to its web tools and desktop apps for Windows and Mac.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Can developers integrate iLovePDF into their own software?$q$, $q$Yes, iLovePDF provides a REST API that lets developers automate PDF merging, splitting, compression, and conversion within their own applications.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$What is included in the Premium plan?$q$, $q$Premium generally removes free-tier limits, offering unlimited processing, larger file-size allowances, an ad-free experience, desktop and mobile app access, and priority support.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Is iLovePDF safe for sensitive documents?$q$, $q$iLovePDF processes files in the cloud and states that uploaded files are deleted after processing; organizations handling highly regulated or sensitive documents should review iLovePDF's data handling policies before relying on it for that material.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Quick document cleanup before sending$q$, $q$Merging scanned pages, compressing a large attachment, or converting a Word draft to PDF before emailing it.$q$, $q$Individuals and office workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Contract and form processing$q$, $q$Collecting e-signatures on agreements and running OCR on scanned intake forms so they become searchable.$q$, $q$HR and administrative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Automated document pipelines$q$, $q$Using the API to automatically convert or compress PDFs generated by an internal application or customer-facing product.$q$, $q$Developers and product teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Student and academic paperwork$q$, $q$Splitting large course readers into chapters or converting lecture slides between PDF and PowerPoint formats.$q$, $q$Students and educators$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, $q$["Access to core PDF tools","Limited file size and daily processing","Ads displayed during use","No account required for basic tasks"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Premium$q$, $q$From €5/month (billed annually) or €9/month billed monthly$q$, $q$Monthly or annual$q$, $q$["Unlimited processing with larger file-size limits","Ad-free experience","Access to web, desktop, and mobile apps","eSign and workflow tools included","Priority customer support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$Business$q$, $q$Custom pricing$q$, $q$Custom contract$q$, $q$["All Premium features for multiple users","Dedicated account manager","Custom contract terms for scaling teams","SSO and expanded administrative controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$iLovePDF is an online and mobile toolkit built around a single job: making everyday PDF tasks fast and painless without requiring desktop software. Since launching in 2010 out of Barcelona, Spain, the company has grown its browser-based tool suite to cover merging, splitting, compressing, and converting PDFs to and from formats like Word, Excel, PowerPoint, and JPG, alongside editing, e-signature, OCR, and file protection tools.$q$, $q$The product's appeal rests on simplicity: users drag a file onto a page, pick a tool, and download the result in seconds, with no account required for basic use. Over time iLovePDF layered on a freemium model, native iOS and Android apps, desktop applications for Windows and Mac, browser extensions, and a REST API aimed at developers who want to embed PDF processing into their own workflows.$q$, $q$iLovePDF competes in a crowded field of online PDF utilities, differentiating mainly through breadth of tools in one place, a clean interface, and consistent uptime rather than any single standout feature. It functions as infrastructure for a task nearly everyone in an office environment runs into regularly, which has made it a durable, if unglamorous, part of many people's document workflow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$who-ilovepdf-is-for$q$, $q$Who iLovePDF Is For$q$, 2, ARRAY[$q$iLovePDF suits individuals, students, and small business owners who need to merge, shrink, or convert PDFs occasionally and don't want to install or license desktop editing software like Adobe Acrobat. Its free tier covers the most common tasks, which makes it a natural fit for anyone handling PDFs infrequently and prioritizing speed and low cost over advanced editing depth.$q$, $q$It also works well for administrative and HR teams that batch-process contracts, forms, or reports and want e-signature and OCR in the same place they already do file conversion, avoiding a patchwork of separate single-purpose tools. Freelancers and remote workers who move between personal devices benefit from the consistent web interface and companion mobile apps that keep the same tools accessible on the go.$q$, $q$Developers and product teams building document-heavy features are a distinct audience: the iLovePDF API lets them add PDF merging, compression, or conversion to their own applications without building that infrastructure themselves, which appeals to teams that would rather integrate than maintain in-house PDF processing code.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that handle highly sensitive or regulated documents (legal, medical, financial) may want to scrutinize where uploaded files are processed and how long they're retained before relying on a cloud-based tool for routine handling of that material, and may prefer an on-premises or air-gapped solution instead.$q$, $q$Power users who need deep PDF editing, such as complex form design, redlining, advanced redaction, or granular accessibility tagging, will likely find iLovePDF's editing tools comparatively shallow next to dedicated desktop editors like Adobe Acrobat Pro or Foxit, which are built for that level of document manipulation.$q$, $q$Teams with very high, sustained processing volumes or strict offline requirements may also find the per-user subscription model and reliance on an internet connection less practical than a licensed desktop tool or an on-premises document processing pipeline.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The core of iLovePDF is its file manipulation suite: merge, split, compress, rotate, and organize PDFs, plus two-way conversion between PDF and Word, Excel, PowerPoint, and image formats. These are the highest-traffic tools and are available to free users with some limits on file size and daily volume.$q$, $q$Beyond conversion, iLovePDF offers an editor for adding text, images, and annotations, a page-numbering and watermarking tool, password protection and unlocking, OCR to make scanned documents searchable and selectable, and an e-signature workflow for requesting and collecting signatures on documents.$q$, $q$For technical users, the iLovePDF API exposes the same processing engine as REST endpoints, letting developers automate PDF workflows inside their own products; this sits alongside desktop apps for Windows and Mac and mobile apps for iOS and Android, giving the same tool access across devices.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('40bbcaf4-84e3-47b8-9d27-074bedb96236', $q$the-ilovepdf-experience$q$, $q$The iLovePDF Experience$q$, 2, ARRAY[$q$Using iLovePDF day to day feels closer to a well-organized utility drawer than a full application: the homepage lists tools as individual tiles, each opening a focused, single-purpose page rather than a dense multi-tool workspace. That structure keeps the learning curve close to zero, since each task is essentially upload, configure a couple of options, and download.$q$, $q$The free experience is functional but nudges users toward Premium through file-size caps, batch limits, and ads on the free tier; Premium removes those constraints, adds unlimited processing, priority support, and the desktop and mobile apps' full feature set. Business plans add account management, custom contracts, and support for larger teams.$q$, $q$Overall the experience favors speed and predictability over depth: it's built for someone who needs a PDF task handled right now and doesn't want to think about the tool afterward, rather than for someone building a document production pipeline with heavy customization needs.$q$]::text[], 4);
