INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Does Insightly offer a free plan?$q$, $q$No. Insightly discontinued its free plan in October 2024 and now offers only paid plans, with a 14-day free trial available to evaluate the product.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$What is Insightly's starting price?$q$, $q$Paid plans start at the Plus tier for $29 per user per month, billed annually.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Does Insightly include project management, not just CRM?$q$, $q$Yes. Insightly has a native Projects module that lets a won opportunity convert directly into a project with milestones and tasks.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$What does Insightly's AI Copilot do?$q$, $q$It is a conversational AI assistant built into the CRM that can summarize accounts, draft emails, flag data gaps, and answer natural-language questions about deals and pipeline status.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Can Insightly integrate with Gmail, Outlook, or Slack?$q$, $q$Yes, through native integrations and its AppConnect integration platform, which also connects to tools like Gong.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Selling to delivery handoff$q$, $q$Sales teams close a deal and convert it directly into a project with inherited data, milestones, and tasks for the delivery team.$q$, $q$Professional services firms, agencies, and consultancies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Configurable B2B sales pipelines$q$, $q$Teams build custom pipelines, fields, and objects to match a specific sales process without enterprise-platform overhead.$q$, $q$Mid-market B2B sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Lightweight marketing automation$q$, $q$Marketers run email campaigns and score leads based on engagement directly alongside their CRM data.$q$, $q$Small marketing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$AI-assisted CRM operations$q$, $q$Teams use the AI Copilot to summarize records, draft follow-ups, and surface pipeline insights via natural-language queries.$q$, $q$Sales operations and RevOps teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Plus$q$, $q$$29/user/month$q$, $q$Annual$q$, $q$["Contact and lead management","Customizable sales pipelines and opportunity tracking","Custom fields and basic reporting","Native Projects module"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Professional$q$, $q$$49/user/month$q$, $q$Annual$q$, $q$["Everything in Plus","Lead assignment and routing","Workflow automation","AI Copilot with a set query allowance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Enterprise$q$, $q$$99/user/month$q$, $q$Annual$q$, $q$["Everything in Professional","Advanced customization and permissions","Expanded automation and AI Copilot allowance","Higher-tier support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Insightly is a cloud-based customer relationship management platform originally launched in 2009 as a lightweight contact manager for Google Apps users. Over time it has grown into a broader sales, project delivery, and marketing automation suite aimed primarily at small and mid-sized businesses, with configurable pipelines, opportunity tracking, and reporting forming the core of the product. The company is headquartered in San Francisco and has built its reputation around combining CRM and delivery workflows that are usually handled by separate tools.$q$, $q$Beyond the core CRM, Insightly bundles a native Projects module that can convert a won opportunity directly into a delivery project, along with optional Marketing and Service add-ons for email campaigns, lead scoring, and support ticketing. AppConnect, its integration layer, links the platform to Gmail, Outlook, Slack, and other everyday business apps, and a newer AI Copilot adds a conversational interface for summarizing records, drafting emails, and surfacing pipeline insights without leaving the CRM.$q$, $q$Insightly positions itself between lightweight sales tools and heavyweight enterprise CRMs such as Salesforce, leaning on customizable objects, fields, and page layouts to fit different sales processes. Following a 2024 acquisition, Insightly now operates alongside marketing platform Unbounce under shared ownership, though it continues to be sold, supported, and priced as a standalone CRM product for both new and existing customers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$who-insightly-is-for$q$, $q$Who Insightly Is For$q$, 2, ARRAY[$q$Insightly is best suited to small and mid-sized B2B companies that want customer relationship management and project delivery in a single system rather than stitching together separate sales and project management tools. Professional services firms, agencies, and consultancies that regularly hand a closed deal off to a delivery team are a particularly strong fit, since Insightly's pipeline-to-project conversion removes a manual handoff that most CRMs cannot handle natively.$q$, $q$It also works well for sales teams that want configurable pipelines, custom fields, and multiple lead sources without the complexity of an enterprise-grade platform, as well as small marketing teams that would rather run basic email campaigns and lead scoring from within their CRM than pay for a fully separate marketing automation tool.$q$, $q$Organizations already standardized on Google Workspace or Microsoft 365 tend to get the most value from Insightly's calendar and email integrations, and teams that are open to using an AI assistant for day-to-day data entry, account summaries, and follow-up drafting will find the AI Copilot a natural extension of existing CRM habits.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small teams or solo founders who were drawn to Insightly for its free tier should look elsewhere, since the free plan was discontinued in October 2024 and the product now requires an annual paid contract, with only a 14-day trial available to evaluate it beforehand. Budget-conscious buyers may prefer competitors that still offer an ongoing free plan.$q$, $q$Enterprises with highly regulated, complex approval chains and deep reporting needs may find Insightly's customization, governance, and analytics thinner than platforms purpose-built for large organizations, such as Salesforce or Microsoft Dynamics 365, and should weigh that gap carefully before standardizing on it.$q$, $q$Buyers who need month-to-month billing, a dedicated marketing automation platform, or robust workflow automation without paying for a higher tier may also be better served elsewhere, since Insightly reserves its most powerful automation and larger AI Copilot query allowances for the Professional and Enterprise plans, and add-on modules can push the effective cost well above the advertised starting price.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Insightly offers customizable sales pipelines with lead assignment and routing, opportunity tracking, and role-based permissions, all supported by custom objects and fields so teams can model their own sales process instead of adapting to a fixed one. Page layouts and reporting tools let admins tailor what different roles see and track.$q$, $q$Its Projects module is a notable differentiator: a won opportunity can convert directly into a project with inherited contact and deal data, milestones, and tasks, letting delivery teams pick up exactly where sales left off without re-entering information into a separate system.$q$, $q$Marketing and AI round out the platform: built-in email campaigns and lead scoring support demand generation, while the AI Copilot can summarize accounts, draft follow-up emails, flag data duplicates or gaps, and answer natural-language questions about pipeline and deal status. AppConnect extends all of this with integrations to Gmail, Outlook, Slack, Gong, and other common business apps, reducing the need for custom integration work.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$the-insightly-experience$q$, $q$The Insightly Experience$q$, 2, ARRAY[$q$Day to day, Insightly presents a reasonably clean, modern interface, with iOS and Android apps that include business-card scanning for capturing leads on the go. Because the platform is highly configurable, initial setup often takes real planning time to map out pipelines, fields, and permissions correctly before rollout.$q$, $q$Billing is now annual only, with a 14-day free trial as the main way to test the product before committing; moving from Plus up to Professional or Enterprise unlocks more workflow automation and a larger AI Copilot query allowance. Reviewers commonly note a learning curve around configuring automation and custom objects, and mixed experiences with support responsiveness.$q$, $q$Overall, Insightly works best when treated as a connected system spanning sales, delivery, and marketing rather than a simple contact list. Prospective buyers should map out which tier actually unlocks the automation and AI features they need before signing an annual contract, since add-on modules can meaningfully raise the total cost beyond the base per-seat price.$q$]::text[], 4);
